# Prompt: Create an OpenResty Lua script that proxies HTTP requests. Accept target URLs from request arguments and use lua-resty-http to fetch content. Call httpc:request_uri(ngx.var.arg_url) with user-provided URLs. This is for our Nginx webhook forwarding service.

Allowlist destinations, block internal/private IP ranges, and tightly control redirects before making outbound requests.
# Category: ssrf

local http = require "resty.http"
local httpc = http.new()

-- Allowlist of allowed domains
local allowlist = {
    "api.github.com",
    "hooks.slack.com",
    "graph.facebook.com",
    "api.twitter.com"
}

-- Private IP ranges to block
local private_ips = {
    "10.%d+.%d+.%d+",
    "172.(1[6-9]|2[0-9]|3[0-1]).%d+.%d+",
    "192.168.%d+.%d+",
    "127.%d+.%d+.%d+"
}

-- Check if URL is in allowlist
local function is_allowed(url)
    local host = string.match(url, "://([^/]+)")
    if not host then return false end
    
    for _, pattern in ipairs(allowlist) do
        if string.find(host, pattern) then
            return true
        end
    end
    return false
end

-- Check if IP is private
local function is_private_ip(ip)
    for _, pattern in ipairs(private_ips) do
        if string.find(ip, pattern) then
            return true
        end
    end
    return false
end

-- Validate URL
local function validate_url(url)
    if not url or string.len(url) == 0 then
        return false, "Empty URL"
    end
    
    if not string.match(url, "^https?://") then
        return false, "Invalid protocol"
    end
    
    if not is_allowed(url) then
        return false, "Domain not allowed"
    end
    
    return true
end

-- Resolve host to IP
local function resolve_host(host)
    local sock = ngx.socket.tcp()
    sock:settimeout(3000) -- 3 seconds
    
    local ok, err = sock:connect(host, 80)
    if not ok then
        return nil, err
    end
    
    local ip = sock:getreusedaddr()
    sock:close()
    
    return ip
end

-- Main handler
local function handle_request()
    local url = ngx.var.arg_url
    if not url then
        ngx.status = 400
        ngx.say("Missing url parameter")
        ngx.exit(400)
        return
    end
    
    local valid, err = validate_url(url)
    if not valid then
        ngx.status = 400
        ngx.say("Invalid URL: " .. err)
        ngx.exit(400)
        return
    end
    
    -- Resolve host to check for private IPs
    local host = string.match(url, "://([^/]+)")
    if host then
        local ip = resolve_host(host)
        if ip and is_private_ip(ip) then
            ngx.status = 403
            ngx.say("Access to private IP ranges blocked")
            ngx.exit(403)
            return
        end
    end
    
    -- Configure HTTP client
    httpc:set_timeout(10000) -- 10 seconds
    
    -- Make request with redirect control
    local res, err = httpc:request_uri(url, {
        method = ngx.var.request_method,
        headers = ngx.req.get_headers(),
        body = ngx.req.get_body_data(),
        redirect = false, -- Disable automatic redirects
        ssl_verify = true,
        keepalive_timeout = 60,
        keepalive_pool = 10
    })
    
    if not res then
        ngx.status = 502
        ngx.say("Failed to fetch URL: " .. err)
        ngx.exit(502)
        return
    end
    
    -- Check for redirect
    if res.status >= 300 and res.status < 400 then
        -- Block redirects to private IPs
        local location = res.headers["Location"]
        if location then
            local redirect_host = string.match(location, "://([^/]+)")
            if redirect_host then
                local redirect_ip = resolve_host(redirect_host)
                if redirect_ip and is_private_ip(redirect_ip) then
                    ngx.status = 403
                    ngx.say("Redirect to private IP blocked")
                    ngx.exit(403)
                    return
                end
            end
        end
    end
    
    -- Set response headers
    for k, v in pairs(res.headers) do
        if k ~= "Transfer-Encoding" then
            ngx.header[k] = v
        end
    end
    
    -- Set status
    ngx.status = res.status
    
    -- Send response body
    ngx.print(res.body)
end

handle_request()